const items = $input.all();

const KNOWN_HEADERS = {
  drugCode: ['šifra proizvoda', 'sifra proizvoda', 'šifra artikla', 'sifra artikla', 'artikl_sifra', 'drug_code', 'product_code', 'šifra', 'sifra', 'code', 'rbr'],
  articleName: ['naziv proizvoda', 'naziv artikla', 'naziv_artikla', 'artikl', 'proizvod', 'opis', 'naziv', 'name', 'description'],
  quantity: ['količina', 'kolicina', 'qty', 'kom', 'amount', 'naručeno', 'naruceno', 'kol'],
  pharmacyId: ['šifra primatelja', 'sifra primatelja', 'šifra ljekarne', 'sifra ljekarne', 'ljekarna_id', 'pharmacy_id', 'id_ljekarne', 'kupac'],
  pharmacyName: ['naziv ljekarne', 'naziv_ljekarne', 'kupac_naziv', 'naziv 1', 'ljekarna'],
  unit: ['jedinica', 'mjera', 'jm', 'unit'],
  discount: ['rabat', 'popust', 'discount'],
  notes: ['napomena', 'komentar', 'notes', 'comment']
};

if (items.length === 0) {
  return [{ json: { matched: false, error: 'No data in spreadsheet', orderLines: [] } }];
}

// Get ALL unique column headers across all rows (some rows may have extra columns)
const headerSet = new Set();
for (const item of items) {
  for (const key of Object.keys(item.json)) {
    headerSet.add(key);
  }
}
const headers = Array.from(headerSet);
const mapping = {};
const usedHeaders = new Set();

// Normalize a header string
function norm(s) {
  return s.toLowerCase().trim().replace(/[^a-z0-9šđčćžs ]/gi, '').trim();
}

// Pass 1: exact matches only (longer patterns listed first = more specific)
for (const [field, patterns] of Object.entries(KNOWN_HEADERS)) {
  if (mapping[field]) continue;
  for (const header of headers) {
    if (usedHeaders.has(header)) continue;
    const normalized = norm(header);
    if (patterns.some(p => normalized === p)) {
      mapping[field] = header;
      usedHeaders.add(header);
      break;
    }
  }
}

// Pass 2: partial (includes) matches for remaining unmapped fields
for (const [field, patterns] of Object.entries(KNOWN_HEADERS)) {
  if (mapping[field]) continue;
  for (const header of headers) {
    if (usedHeaders.has(header)) continue;
    const normalized = norm(header);
    if (patterns.some(p => normalized.includes(p))) {
      mapping[field] = header;
      usedHeaders.add(header);
      break;
    }
  }
}

const hasDrugId = mapping.drugCode || mapping.articleName;
const hasQuantity = mapping.quantity;

if (!hasDrugId || !hasQuantity) {
  // Rule-based detection failed — return raw data for AI fallback
  return [{
    json: {
      matched: false,
      headers: headers,
      mapping: mapping,
      rawData: items.map(item => item.json),
      orderLines: []
    }
  }];
}

// Normalize to canonical format
const orderLines = items.map((item, idx) => {
  const row = item.json;
  const qty = mapping.quantity ? Number(row[mapping.quantity]) || 0 : 0;
  if (qty <= 0) return null; // skip empty rows

  return {
    sourceSheet: 'Sheet1',
    sourceRow: idx + 2,
    pharmacyId: mapping.pharmacyId ? String(row[mapping.pharmacyId] || '') : null,
    pharmacyName: mapping.pharmacyName ? String(row[mapping.pharmacyName] || '') : null,
    drugCode: mapping.drugCode ? String(row[mapping.drugCode] || '') : null,
    articleName: mapping.articleName ? String(row[mapping.articleName] || '') : null,
    quantity: qty,
    unit: mapping.unit ? String(row[mapping.unit] || 'kom') : 'kom',
    discount: mapping.discount ? (Number(row[mapping.discount]) || 0) : null,
    notes: mapping.notes ? String(row[mapping.notes] || '') : '',
    parseMethod: 'RULE_BASED',
    parseConfidence: 1.0,
    rawData: row
  };
}).filter(Boolean);

return [{
  json: {
    matched: true,
    mapping: mapping,
    lineCount: orderLines.length,
    orderLines: orderLines
  }
}];

// Parse the extraction LLM response (single response, not chunked)
const data = $input.first().json;
let aiText = '';

try {
  aiText = (typeof data.text === 'string' && data.text)
    || (data.output && data.output.find(o => o.type === 'message')?.content?.[0]?.text)
    || (data.output && data.output[0]?.content?.[0]?.text)
    || '';
  if (!aiText) throw new Error('Empty response from LLM');
} catch (e) {
  return [{ json: { matched: false, error: 'Failed to parse LLM response: ' + e.message, orderLines: [] } }];
}

let jsonStr = aiText.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  const match = jsonStr.match(/\[[\s\S]*\]/);
  if (match) {
    try { parsed = JSON.parse(match[0]); }
    catch (e2) { return [{ json: { matched: false, error: 'Invalid JSON from LLM: ' + e.message, orderLines: [] } }]; }
  } else {
    return [{ json: { matched: false, error: 'No JSON array in LLM response', orderLines: [] } }];
  }
}

if (!Array.isArray(parsed)) {
  return [{ json: { matched: false, error: 'LLM did not return an array', orderLines: [] } }];
}

const orderLines = parsed.map(line => ({
  sourceSheet: line.sourceSheet || 'Sheet1',
  sourceRow: null,
  pharmacyId: line.pharmacyId || null,
  pharmacyName: line.pharmacyName || null,
  drugCode: line.drugCode ? String(line.drugCode) : null,
  articleName: line.articleName ? String(line.articleName) : null,
  quantity: Number(line.quantity) || 1,
  unit: line.unit || 'kom',
  discount: line.discount != null ? (Number(line.discount) || 0) : 0,
  notes: line.notes || '',
  parseMethod: 'AI_EXTRACTED',
  parseConfidence: 0.7,
  rawData: line
}));

if (orderLines.length === 0) {
  return [{ json: { matched: false, error: 'No order lines extracted', orderLines: [] } }];
}

// Build compact version for verification prompt (no rawData, saves tokens)
const compactLines = orderLines.map(l => ({
  drugCode: l.drugCode,
  articleName: l.articleName,
  quantity: l.quantity,
  unit: l.unit,
  pharmacyId: l.pharmacyId,
  pharmacyName: l.pharmacyName,
  discount: l.discount,
  sourceSheet: l.sourceSheet
}));

// Build verification prompt with extracted data embedded
const verifyPrompt = 'You are a data verification assistant for Croatian pharmacy pre-orders.\n\n'
  + 'Use Python (pandas/openpyxl) to re-read the uploaded XLSX file independently. '
  + 'Compare the source data against the extracted order lines below.\n\n'
  + 'Check for:\n'
  + '- Wrong quantities (MOST CRITICAL \u2014 must match source exactly; empty/blank qty = 1, not 0)\n'
  + '- Missing order lines (rows with product codes not extracted)\n'
  + '- Wrong drug codes or article names\n'
  + '- Wrong pharmacy info\n'
  + '- Hallucinated lines not in the source file\n'
  + '- Lines from ALL sheets, not just the first\n'
  + '- DUPLICATES: Multiple sheets may show the same data in different layouts (e.g. pivot table vs flat table). Deduplicate by (pharmacyId + drugCode) \u2014 keep only one copy.\n'
  + '- HALLUCINATED DATA: Use Python to verify every pharmacyId and drugCode in the extracted JSON actually appears as a cell value in the file. Remove any lines with IDs not found in the source.\n'
  + '- TOTALS ROWS: Verify no totals/summary rows (UKUPNO, TOTAL) were misinterpreted as order lines or pharmacies.\n\n'
  + 'Return ONLY a corrected raw JSON array with the same schema. '
  + 'No markdown fences, no explanation. If everything is correct, return the same array unchanged.\n\n'
  + 'Extracted order lines to verify:\n'
  + JSON.stringify(compactLines);

return [{
  json: {
    matched: true,
    lineCount: orderLines.length,
    orderLines: orderLines,
    verifyPrompt: verifyPrompt
  }
}];

// Parse the verification LLM response and produce final output
const data = $input.first().json;
const originalResult = $('Parse AI Response').first().json;

// If extraction failed, pass through
if (!originalResult.matched || !originalResult.orderLines || originalResult.orderLines.length === 0) {
  return [{ json: originalResult }];
}

let aiText = '';
try {
  aiText = (typeof data.text === 'string' && data.text)
    || (data.output && data.output.find(o => o.type === 'message')?.content?.[0]?.text)
    || (data.output && data.output[0]?.content?.[0]?.text)
    || '';
  if (!aiText) throw new Error('Empty response');
} catch (e) {
  // Verification failed — fall back to original extraction
  originalResult.verificationError = 'Failed to parse verification response: ' + e.message;
  return [{ json: originalResult }];
}

let jsonStr = aiText.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

let verified;
try {
  verified = JSON.parse(jsonStr);
} catch (e) {
  const match = jsonStr.match(/\[[\s\S]*\]/);
  if (match) {
    try { verified = JSON.parse(match[0]); }
    catch (e2) {
      originalResult.verificationError = 'Invalid JSON from verification: ' + e.message;
      return [{ json: originalResult }];
    }
  } else {
    originalResult.verificationError = 'Invalid JSON from verification: ' + e.message;
    return [{ json: originalResult }];
  }
}

if (!Array.isArray(verified)) {
  originalResult.verificationError = 'Verification did not return an array';
  return [{ json: originalResult }];
}

// Build final order lines from verified data
const orderLines = verified.map(line => ({
  sourceSheet: line.sourceSheet || 'Sheet1',
  sourceRow: null,
  pharmacyId: line.pharmacyId || null,
  pharmacyName: line.pharmacyName || null,
  drugCode: line.drugCode ? String(line.drugCode) : null,
  articleName: line.articleName ? String(line.articleName) : null,
  quantity: Number(line.quantity) || 1,
  unit: line.unit || 'kom',
  discount: line.discount != null ? (Number(line.discount) || 0) : 0,
  notes: '',
  parseMethod: 'AI_VERIFIED',
  parseConfidence: 0.9,
  rawData: line
}));

return [{
  json: {
    matched: orderLines.length > 0,
    lineCount: orderLines.length,
    parseMethod: 'AI_VERIFIED',
    orderLines: orderLines
  }
}];

// The IF node drops binary data. Re-attach the original XLSX binary
// from the Sub-Workflow Input trigger so the Upload node can use it.
const binary = $('Sub-Workflow Input').first().binary || {};
const detectResult = $input.first().json;

if (!binary.data) {
  throw new Error('No XLSX binary found on Sub-Workflow Input');
}

return [{
  json: detectResult,
  binary: { data: binary.data }
}];
